const InfoText = styled.p`
  color: ${({ theme }) => theme.colors.textLight};
  font-size: 0.9rem;
  margin: 0.5rem 0;
`;

const getVenueTypeTranslation = (venueType) => {
  switch (venueType) {
    case 'supermarket':
      return '–°—Г–њ–µ—А–Љ–∞—А–Ї–µ—В—Л';
    case 'pharmacy':
      return '–Р–њ—В–µ–Ї–Є';
    default:
      return venueType;
  }
};

const StoreList = () => {
  const { t } = useTranslation();
  const [selectedVenueType, setSelectedVenueType] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [venueTypes, setVenueTypes] = useState([]);
  const [isLoadingVenueTypes, setIsLoadingVenueTypes] = useState(true);
  const [userLocations, setUserLocations] = useState([]);
  const [isLoadingLocations, setIsLoadingLocations] = useState(true);
  const [selectedLocation, setSelectedLocation] = useState(null);
  const [stores, setStores] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // –Ч–∞–≥—А—Г–Ј–Ї–∞ —В–Є–њ–Њ–≤ –Ј–∞–≤–µ–і–µ–љ–Є–є –њ—А–Є –Љ–Њ–љ—В–Є—А–Њ–≤–∞–љ–Є–Є –Ї–Њ–Љ–њ–Њ–љ–µ–љ—В–∞
  useEffect(() => {
    const fetchVenueTypes = async () => {
      try {
        const types = await getVenueTypes();
        setVenueTypes(types);
      } catch (error) {
        console.error('Error fetching venue types:', error);
      } finally {
        setIsLoadingVenueTypes(false);
      }
    };

    fetchVenueTypes();
  }, []);

  // –Ч–∞–≥—А—Г–Ј–Ї–∞ –ї–Њ–Ї–∞—Ж–Є–є –њ–Њ–ї—М–Ј–Њ–≤–∞—В–µ–ї—П
  useEffect(() => {
    const fetchUserLocations = async () => {
      try {
        setIsLoadingLocations(true);
        // –Ш—Б–њ–Њ–ї—М–Ј—Г–µ–Љ –≤—А–µ–Љ–µ–љ–љ—Л–є ID –њ–Њ–ї—М–Ј–Њ–≤–∞—В–µ–ї—П –і–ї—П –і–µ–Љ–Њ–љ—Б—В—А–∞—Ж–Є–Є
        // –Т —А–µ–∞–ї—М–љ–Њ–Љ –њ—А–Є–ї–Њ–ґ–µ–љ–Є–Є –љ—Г–ґ–љ–Њ –Є—Б–њ–Њ–ї—М–Ј–Њ–≤–∞—В—М ID –∞–≤—В–Њ—А–Є–Ј–Њ–≤–∞–љ–љ–Њ–≥–Њ –њ–Њ–ї—М–Ј–Њ–≤–∞—В–µ–ї—П
        const userId = localStorage.getItem('userId') || '1';
        const locations = await getUserLocations(userId);
        setUserLocations(locations);

        // –Х—Б–ї–Є –ї–Њ–Ї–∞—Ж–Є–Є –µ—Б—В—М, –≤—Л–±–Є—А–∞–µ–Љ –њ–µ—А–≤—Г—О –њ–Њ —Г–Љ–Њ–ї—З–∞–љ–Є—О
        if (locations.length > 0) {
          setSelectedLocation(locations[0]);
        }
      } catch (error) {
        console.error('Error fetching user locations:', error);
      } finally {
        setIsLoadingLocations(false);
      }
    };

    fetchUserLocations();
  }, []);

  // –Ч–∞–≥—А—Г–Ј–Ї–∞ –Љ–∞–≥–∞–Ј–Є–љ–Њ–≤ –≤ –Ј–∞–≤–Є—Б–Є–Љ–Њ—Б—В–Є –Њ—В –≤—Л–±—А–∞–љ–љ–Њ–є –ї–Њ–Ї–∞—Ж–Є–Є –Є —В–Є–њ–∞ –Ј–∞–≤–µ–і–µ–љ–Є—П
  useEffect(() => {
    const fetchStores = async () => {
      try {
        setLoading(true);
        setError(null);

        let storesData;

        if (selectedLocation) {
          // –Х—Б–ї–Є –≤—Л–±—А–∞–љ–∞ –ї–Њ–Ї–∞—Ж–Є—П, –Ј–∞–≥—А—Г–ґ–∞–µ–Љ –Љ–∞–≥–∞–Ј–Є–љ—Л –≤ —А–∞–і–Є—Г—Б–µ 3 –Ї–Љ –Њ—В –љ–µ—С
          storesData = await getStoresByLocation(
            selectedLocation.lat,
            selectedLocation.lon,
            3.0,
            selectedVenueType
          );
        } else {
          // –Х—Б–ї–Є –ї–Њ–Ї–∞—Ж–Є—П –љ–µ –≤—Л–±—А–∞–љ–∞, –Ј–∞–≥—А—Г–ґ–∞–µ–Љ –≤—Б–µ –Љ–∞–≥–∞–Ј–Є–љ—Л
          storesData = await getStoresWithDiscounts(selectedVenueType);
        }

        setStores(storesData);
      } catch (error) {
        console.error('Error fetching stores:', error);
        setError(error);
      } finally {
        setLoading(false);
      }
    };

    fetchStores();
  }, [selectedLocation, selectedVenueType]);

  // –§–Є–ї—М—В—А–∞—Ж–Є—П –Љ–∞–≥–∞–Ј–Є–љ–Њ–≤ –њ–Њ –њ–Њ–Є—Б–Ї–Њ–≤–Њ–Љ—Г –Ј–∞–њ—А–Њ—Б—Г
  const filteredStores = stores?.filter(store => 
    store.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // –Ю–±—А–∞–±–Њ—В—З–Є–Ї –Є–Ј–Љ–µ–љ–µ–љ–Є—П –≤—Л–±—А–∞–љ–љ–Њ–є –ї–Њ–Ї–∞—Ж–Є–Є
  const handleLocationChange = (e) => {
    const locationId = e.target.value;
    if (locationId === 'all') {
      setSelectedLocation(null);
    } else {
      const location = userLocations.find(loc => loc.id.toString() === locationId);
      setSelectedLocation(location);
    }
  };

  return (
    <Container>
      <HeaderContainer>
        <Title>{t('storesWithDiscounts')}</Title>
        <SearchContainer>
          <SearchInput 
            type="text" 
            placeholder={t('searchStores')}
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <SearchIcon>рЯФН</SearchIcon>
        </SearchContainer>
      </HeaderContainer>

      <FiltersContainer>
        {!isLoadingLocations && (
          <div>
            <LocationSelect 
              value={selectedLocation ? selectedLocation.id : 'all'} 
              onChange={handleLocationChange}
            >
              <option value="all">–Т—Б–µ –ї–Њ–Ї–∞—Ж–Є–Є</option>
              {userLocations.map(location => (
                <option key={location.id} value={location.id}>
                  {location.name || `–Ы–Њ–Ї–∞—Ж–Є—П ${location.id}`}
                </option>
              ))}
            </LocationSelect>
            {selectedLocation && (
              <InfoText>
                –Я–Њ–Ї–∞–Ј–∞–љ—Л –Љ–∞–≥–∞–Ј–Є–љ—Л –≤ —А–∞–і–Є—Г—Б–µ 3 –Ї–Љ –Њ—В –≤—Л–±—А–∞–љ–љ–Њ–є –ї–Њ–Ї–∞—Ж–Є–Є
              </InfoText>
            )}
          </div>
        )}

        {!isLoadingVenueTypes && venueTypes.length > 0 && (
          <VenueTypeMenu>
            <VenueTypeButton 
              active={selectedVenueType === null} 
              onClick={() => setSelectedVenueType(null)}
            >
              {t('all')}
            </VenueTypeButton>
            {venueTypes.map(type => (
              <VenueTypeButton 
                key={type} 
                active={selectedVenueType === type} 
                onClick={() => setSelectedVenueType(type)}
              >
                {type === 'supermarket' ? t('supermarkets') : t('pharmacies')}
              </VenueTypeButton>
            ))}
          </VenueTypeMenu>
        )}
      </FiltersContainer>

      {loading ? (
        <Loading />
      ) : error ? (
        <Error onRetry={() => {
          // –Я–µ—А–µ–Ј–∞–≥—А—Г–ґ–∞–µ–Љ –Љ–∞–≥–∞–Ј–Є–љ—Л
          if (selectedLocation) {
            getStoresByLocation(
              selectedLocation.lat,
              selectedLocation.lon,
              3.0,
              selectedVenueType
            ).then(data => setStores(data)).catch(err => setError(err));
          } else {
            getStoresWithDiscounts(selectedVenueType)
              .then(data => setStores(data))
              .catch(err => setError(err));
          }
        }} />
      ) : filteredStores && filteredStores.length > 0 ? (
        <Grid>
          {filteredStores.map(store => (
            <StoreCard key={store.id} store={store} />
          ))}
        </Grid>
      ) : (
        <EmptyState>
          {searchTerm ? (
            <p>{t('noSearchResults')}</p>
          ) : selectedVenueType ? (
            <p>–Э–µ—В –Љ–∞–≥–∞–Ј–Є–љ–Њ–≤ —Б –∞–Ї—Ж–Є—П–Љ–Є –≤ –Ї–∞—В–µ–≥–Њ—А–Є–Є {getVenueTypeTranslation(selectedVenueType)}</p>
          ) : selectedLocation ? (
            <p>–Э–µ—В –Љ–∞–≥–∞–Ј–Є–љ–Њ–≤ —Б –∞–Ї—Ж–Є—П–Љ–Є –≤ —А–∞–і–Є—Г—Б–µ 3 –Ї–Љ –Њ—В –≤—Л–±—А–∞–љ–љ–Њ–є –ї–Њ–Ї–∞—Ж–Є–Є</p>
          ) : (
            <p>{t('noDiscounts')}</p>
          )}
        </EmptyState>
      )}
      <ScrollToTopButton />
    </Container>
  );
};

export default StoreList;
